let gameSession=window.__gongxingGameSession,accessTimer=0,accessExpired=false;
if(!gameSession)throw new Error('A valid redeemed game session is required.');
function validGameSession(s){return !!(s&&s.version===1&&Number.isFinite(s.issuedAt)&&Number.isFinite(s.expiresAt)&&Number.isInteger(s.minutes)&&s.minutes>=1&&s.minutes<=15&&s.cost===s.minutes*5&&s.expiresAt-s.issuedAt<=s.minutes*60000+1500&&s.expiresAt>Date.now())}
function formatPlayTime(ms){const seconds=Math.max(0,Math.ceil(ms/1000)),minutes=Math.floor(seconds/60);return `${minutes}:${String(seconds%60).padStart(2,'0')}`}
function expireGameAccess(){if(accessExpired)return;accessExpired=true;clearInterval(accessTimer);cancelAnimationFrame(raf);game?.destroy?.();localStorage.removeItem(GAME_SESSION_KEY);document.body.classList.add('access-expired');location.replace('index.html?gameExpired=1')}
function updatePlayTimer(){if(!validGameSession(gameSession))return expireGameAccess();const text=formatPlayTime(gameSession.expiresAt-Date.now());const top=$('#playTimeTop'),hud=$('#playTimeHud');if(top)top.textContent=text;if(hud)hud.textContent=text}
function recheckGameAccess(){try{const latest=JSON.parse(localStorage.getItem(GAME_SESSION_KEY)||'null');if(validGameSession(latest)){gameSession=latest;updatePlayTimer()}else expireGameAccess()}catch{expireGameAccess()}}
